  1	import * as React from 'react';
  2	import {
  3	  useCustomTranslation,
  4	  TypeaheadDropdown,
  5	  CAPACITY_AUTOSCALING_MAX_LIMIT_IN_TIB,
  6	  CAPACITY_OSD_MAX_SIZE_IN_TIB,
  7	  StorageSizeUnit,
  8	} from '@odf/shared';
  9	import {
 10	  formatCapacityText,
 11	  formatCapacityValue,
 12	  getStorageSizeInTiBWithoutUnit,
 13	} from '@odf/shared/utils';
 14	import {
 15	  Alert,
 16	  AlertVariant,
 17	  Button,
 18	  ButtonVariant,
 19	  Checkbox,
 20	  Label,
 21	  Popover,
 22	  SelectOptionProps,
 23	} from '@patternfly/react-core';
 24	import './capacity-autoscaling.scss';
 25	import { InfoCircleIcon } from '@patternfly/react-icons';
 26	
 27	const getItem = (capacityLimit: number) => ({
 28	  'data-limit': capacityLimit,
 29	  value: formatCapacityValue(`${capacityLimit}${StorageSizeUnit.Ti}`),
 30	  children: formatCapacityText(`${capacityLimit}${StorageSizeUnit.Ti}`),
 31	});
 32	
 33	const getCapacityLimitDropdownItems = (
 34	  osdAmount: number,
 35	  osdSize: number,
 36	  capacityLimit: string
 37	): SelectOptionProps[] => {
 38	  const items = [];
 39	  if (osdSize <= 0 || osdAmount <= 0) {
 40	    return items;
 41	  }
 42	
 43	  let capacity = osdSize * osdAmount;
 44	
 45	  // Vertical scaling.
 46	  while (osdSize * 2 <= CAPACITY_OSD_MAX_SIZE_IN_TIB) {
 47	    osdSize *= 2;
 48	    capacity = osdSize * osdAmount;
 49	    items.push(getItem(capacity));
 50	  }
 51	
 52	  // Horizontal scaling.
 53	  while (
 54	    capacity + osdSize * osdAmount <=
 55	    CAPACITY_AUTOSCALING_MAX_LIMIT_IN_TIB
 56	  ) {
 57	    capacity += osdSize * osdAmount;
 58	    items.push(getItem(capacity));
 59	  }
 60	
 61	  // If capacity limit has been set via CLI and not already included
 62	  // in the items, we include it:
 63	  const itemValues = items.map((item) => item.value);
 64	  if (capacityLimit && !itemValues.includes(capacityLimit)) {
 65	    items.push(getItem(getStorageSizeInTiBWithoutUnit(capacityLimit)));
 66	    items.sort((a, b) => a['data-limit'] - b['data-limit']);
 67	  }
 68	
 69	  return items;
 70	};
 71	
 72	type CapacityAutoScalingProps = {
 73	  capacityLimit: string;
 74	  className?: string;
 75	  enable: boolean;
 76	  isEditView?: boolean;
 77	  onChange: (_ev: React.FormEvent<HTMLInputElement>, checked: boolean) => void;
 78	  onLimitSelect: (selected: string) => void;
 79	  osdAmount: number;
 80	  osdSize: string;
 81	};
 82	
 83	export const CapacityAutoScaling: React.FC<CapacityAutoScalingProps> = ({
 84	  capacityLimit,
 85	  className,
 86	  enable,
 87	  isEditView = false,
 88	  onChange,
 89	  onLimitSelect,
 90	  osdAmount,
 91	  osdSize,
 92	}) => {
 93	  const { t } = useCustomTranslation();
 94	  const capacityItems = React.useMemo(
 95	    () =>
 96	      getCapacityLimitDropdownItems(
 97	        osdAmount,
 98	        getStorageSizeInTiBWithoutUnit(osdSize),
 99	        capacityLimit
100	      ),
101	    [capacityLimit, osdAmount, osdSize]
102	  );
103	  const capacityLimitPlaceHolder = t(
104	    'Select the maximum limit to which the cluster can expand.'
105	  );
106	  return (
107	    <div className={className}>
108	      {!isEditView && (
109	        <div className="pf-v6-u-font-family-heading pf-v6-u-mb-sm">
110	          {t('Automatic capacity scaling')}
111	        </div>
112	      )}
113	      <Checkbox
114	        label={
115	          <span>
116	            {t('Enable automatic capacity scaling for your cluster')}
117	            {isEditView && (
118	              <Label
119	                color="teal"
120	                className="pf-v6-u-ml-sm pf-v6-u-font-size-sm"
121	                icon={<InfoCircleIcon />}
122	                isCompact
123	              >
124	                {t('incur additional costs')}
125	              </Label>
126	            )}
127	          </span>
128	        }
129	        description={
130	          <div>
131	            {t(
132	              'Opt-in to automatically add additional raw capacity equivalent to the configured deployment size whenever used capacity reaches 70%. This ensures your deployment scales seamlessly to meet demand.'
133	            )}
134	            <Popover
135	              aria-label={t('How does automatic capacity scaling work?')}
136	              bodyContent={t(
137	                'Automatic capacity scaling adds capacity through OSD expansion by resizing existing OSDs or adding new OSDs to maintain node balance.'
138	              )}
139	              footerContent={
140	                <>
141	                  <span className="pf-v6-u-font-weight-bold pf-v6-u-mr-xs">
142	                    {t('Note:')}
143	                  </span>
144	                  {t(
145	                    'OSD expansion is limited to a maximum of {{osdMaxSize}}.',
146	                    {
147	                      osdMaxSize: formatCapacityText(
148	                        `${CAPACITY_OSD_MAX_SIZE_IN_TIB}${StorageSizeUnit.Ti}`
149	                      ),
150	                    }
151	                  )}
152	                </>
153	              }
154	            >
155	              <Button
156	                className="odf-capacity-autoscaling__popover-link pf-v6-u-font-size-sm"
157	                variant={ButtonVariant.link}
158	              >
159	                {t('How does it work?')}
160	              </Button>
161	            </Popover>
162	          </div>
163	        }
164	        id="capacity-autoscaling"
165	        data-checked-state={enable}
166	        isChecked={enable}
167	        onChange={onChange}
168	      />
169	      {enable && (
170	        <div className="odf-capacity-limit__section">
171	          <Alert
172	            isInline
173	            title={t(
174	              'This may incur additional costs for the underlying storage.'
175	            )}
176	            variant={AlertVariant.info}
177	          />
178	          <div className="pf-v6-u-font-family-heading">
179	            {t('Cluster expansion limit')}
180	          </div>
181	          <div>
182	            {t(
183	              'The maximum limit to which the cluster can expand in the cloud. Automatic capacity scaling is suspended if exceeded.'
184	            )}
185	          </div>
186	          <TypeaheadDropdown
187	            ariaLabel={capacityLimitPlaceHolder}
188	            className="odf-capacity-limit__selector"
189	            id="cluster-capacity-limit"
190	            items={capacityItems}
191	            onSelect={onLimitSelect}
192	            placeholder={capacityLimitPlaceHolder}
193	            selectedValue={formatCapacityValue(capacityLimit)}
194	          />
195	        </div>
196	      )}
197	    </div>
198	  );
199	};

